#[impl_interface]
impl ArchInterface for ArchInterfaceImpl {
    /// Init allocator
    fn init_allocator() {
        mm::init_heap();
    }
    /// kernel interrupt
    fn kernel_interrupt(ctx: &mut TrapFrame, trap_type: TrapType) {
        // println!("trap_type @ {:x?} {:#x?}", trap_type, ctx);
        //        let curtask = current_task();
        if let Some(task) = current_task() {
            task.inner_exclusive_access().tms.update_utime();
            task.check_itimer();
        }
        //        if curtask.is_some(){
        //            curtask.clone().unwrap().inner_exclusive_access().tms.update_utime();
        //        }
        //        if curtask.is_some(){
        //            curtask.unwrap().check_itimer();
        //        }
        match trap_type {
            Breakpoint => return,
            UserEnvCall => {
                INTERRUPTINFO.lock().1 += 1;
                // jump to next instruction anyway
                ctx.syscall_ok();
                let args = ctx.args();
                // get system call return value
                // info!("syscall: {}", ctx[TrapFrameArgs::SYSCALL]);
                let id = ctx[TrapFrameArgs::SYSCALL];
                let result = syscall(
                    id,
                    [args[0], args[1], args[2], args[3], args[4], args[5]],
                );
                // cx is changed during sys_exec, so we have to call it again
                if id != 93 && id != 139 {
                    //exec sigreturn don't return
                    ctx[TrapFrameArgs::RET] = result as usize; //exec中这一句会干死glibc的动态链接器
                }
            }
            StorePageFault(_paddr) | LoadPageFault(_paddr) | InstructionPageFault(_paddr) => {
                let ctask = current_task().unwrap();
                let inner = ctask.inner_exclusive_access();
                let mut memory_set = inner.memory_set.lock();
                if memory_set.handle_lazy_addr(_paddr, trap_type).is_err() {
                    match trap_type {
                        StorePageFault(_paddr) => {
                            let r = memory_set.handle_cow_addr(_paddr);
                            if r.is_err() {
                                for area in &memory_set.areas {
                                    if area.vpn_range.l.value() <= _paddr >> 12
                                        && _paddr >> 12 < area.vpn_range.r.value()
                                    {
                                        //area.map_perm.show_perm();
                                        if !area.map_perm.contains(MapPermission::W)
                                        {
                                            //访问保护页->SIGEGV，由信号退出
                                            // 构造SigInfo
                                            let sig_info = SigInfo {
                                                signum: 11,
                                                code: SigInfo::USER,
                                                details: SigDetails::Kill {
                                                    pid: ctask.getpid(),
                                                    uid: 0,
                                                },
                                            };
                                            drop(memory_set);
                                            drop(inner);
                                            ctask.add_signal(sig_info);
                                            drop(ctask);
                                            return;
                                        } else {
                                            //area.map_perm.show_perm();
                                            break;
                                        }
                                    }
                                }
                                //       memory_set.debug_addr_info();
                                println!(
                                    "err {:x?},sepc:{:x},sepcpage:{:x} id:{}",
                                    trap_type,
                                    ctx[TrapFrameArgs::SEPC],
                                    ctx[TrapFrameArgs::SEPC] / PAGE_SIZE,
                                    ctask.gettid()
                                );
                                //      ctx.syscall_ok();
                                println!("problem page {:x}", _paddr >> 12);
                                drop(memory_set);
                                drop(inner);
                                drop(ctask);
                                exit_current_and_run_next(-1);
                            }
                        }
                        _ => {
                            let sig_info = SigInfo {
                                signum: 11,
                                code: SigInfo::USER,
                                details: SigDetails::Kill {
                                    pid: ctask.getpid(),
                                    uid: 0,
                                },
                            };
                            let kernel_pc = ctx[TrapFrameArgs::SEPC] >= arch::VIRT_ADDR_START;


