const MODULE_LEVEL:log::Level = log::Level::Trace;
const SCHED_FIFO: u32 = 1;
const SCHED_RR: u32 = 2;
const RT_FETCH_BUDGET: usize = 16;

///A array of `TaskControlBlock` that is thread-safe
pub struct TaskManager {
    ready_queue: VecDeque<Arc<TaskControlBlock>>,//why use Arc:TaskManager->TCB & TCB.children->TCB & TaskManager creates Arc<TCB>
    block_queue: VecDeque<Arc<TaskControlBlock>>,
    rt_fetch_budget: usize,
}

/// A simple FIFO scheduler.
impl TaskManager {
    ///Creat an empty TaskManager
    pub fn new() -> Self {
        Self {
            ready_queue: VecDeque::new(),
            block_queue:VecDeque::new(),
            rt_fetch_budget: RT_FETCH_BUDGET,
        }
    }
    ///Add a task to `TaskManager`
    pub fn add(&mut self, task: Arc<TaskControlBlock>) {
        if self.ready_queue.iter().any(|queued| queued.gettid() == task.gettid()) {
            return;
        }
        self.ready_queue.push_back(task);
    }
    ///Add a blocked task to `TaskManager`
    pub fn add_block(&mut self, task: Arc<TaskControlBlock>) {
        if self.block_queue.iter().any(|queued| queued.gettid() == task.gettid()) {
            return;
        }
        self.block_queue.push_back(task);
    }
    ///Remove the first task and return it,or `None` if `TaskManager` is empty
    pub fn fetch(&mut self) -> Option<Arc<TaskControlBlock>> {
        self.ready_queue
            .retain(|task| task.inner_exclusive_access().task_status != TaskStatus::Zombie);
        let is_truly_blocked = |task: &Arc<TaskControlBlock>| {
            if task.inner_exclusive_access().task_status != TaskStatus::Blocked {
                return false;
            }
            self.block_queue
                .iter()
                .any(|blocked| blocked.gettid() == task.gettid())
        };
        let mut rt_pos = None;
        let mut rt_pid = 0;
        let mut rt_priority = i32::MIN;
        for (pos, task) in self.ready_queue.iter().enumerate() {
            if is_truly_blocked(task) {
                continue;
            }
            let inner = task.inner_exclusive_access();
            let policy = inner.sched_attr.sched_policy;
            if (policy == SCHED_FIFO || policy == SCHED_RR)
                && inner.sched_param.sched_priority > 0
                && inner.sched_param.sched_priority > rt_priority
            {
                rt_pos = Some(pos);
                rt_pid = task.getpid();
                rt_priority = inner.sched_param.sched_priority;
            }
        }
        if rt_pos.is_some() && self.rt_fetch_budget == 0 {
            let same_process_normal_pos = self
                .ready_queue
                .iter()
                .position(|task| !is_truly_blocked(task) && task.getpid() == rt_pid && !is_realtime_task(task));
            if let Some(pos) = same_process_normal_pos {
                self.rt_fetch_budget = RT_FETCH_BUDGET;
                return self.ready_queue.remove(pos);
            }
        }
        if let Some(pos) = rt_pos {
            self.rt_fetch_budget = self.rt_fetch_budget.saturating_sub(1);
            self.ready_queue.remove(pos)
        } else if let Some(pos) = self
            .ready_queue
            .iter()
            .position(|task| !is_truly_blocked(task))
        {
            self.rt_fetch_budget = RT_FETCH_BUDGET;
            self.ready_queue.remove(pos)
        } else {
            self.rt_fetch_budget = RT_FETCH_BUDGET;
            self.ready_queue.pop_front()
        }
    }
    /// 根据 PID 查找任务（仅在就绪队列中查找）
    pub fn find_task_by_tid(&self, tid: usize) -> Option<Arc<TaskControlBlock>> {
        self.ready_queue.iter().find(|task| task.gettid() == tid).cloned()
    }
    pub fn remove_blocked_task_by_tid(&mut self, tid: usize)->Option<Arc<TaskControlBlock>>{
        if let Some(pos) = self.block_queue.iter().position(|task| task.gettid() == tid){
            return self.block_queue.remove(pos);
        }
        else{
            return None;
        }
    }
    pub fn remove_ready_task_by_tid(&mut self, tid: usize)->Option<Arc<TaskControlBlock>>{
        if let Some(pos) = self.ready_queue.iter().position(|task| task.gettid() == tid){
            return self.ready_queue.remove(pos);
        }
        else{
            return None;
        }
    }
}

fn is_realtime_task(task: &Arc<TaskControlBlock>) -> bool {
    let inner = task.inner_exclusive_access();
    let policy = inner.sched_attr.sched_policy;
    (policy == SCHED_FIFO || policy == SCHED_RR) && inner.sched_param.sched_priority > 0
}

