///Interface offered to pop the first task
pub fn wakeup_task(task: Arc<TaskControlBlock>) {
    let mut task_inner = task.inner_exclusive_access();
    // 如果任务已经是 Zombie，说明它已经在 exit 流程中，
    // 不应再放回就绪队列，否则会导致同一个任务多次执行 exit_current_and_run_next。
    if task_inner.task_status == TaskStatus::Zombie {
        return;
    }
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    let mut need_add = false;
    if let Some(_) = TASK_MANAGER.lock().remove_blocked_task_by_tid(task.gettid()){
        need_add = true;
    }
    if need_add{
        add_task(task.clone());
    }
}
