///
#[allow(unused)]
pub fn safe_translated_byte_buffer(
    memory_set: Arc<Mutex<MemorySet>>,
    ptr: *mut u8,
    len: usize,
) -> &'static mut [u8] {
    let mut memory_set = memory_set.lock();
    let page_table = memory_set.page_table.clone();
    let mut start = ptr as usize;
    let end = start + len;
    while start < end {
        let start_va = VirtAddr::from(start);
        let vpn: VirtPage = start_va.into();
        match page_table.translate(vpn.into()) {
            None => {
                let r = memory_set
                    .handle_lazy_addr(start_va.addr(), TrapType::StorePageFault(start_va.addr()));
                if r.is_err() {
                    if let Err(e) = memory_set.handle_cow_addr(start_va.addr()) {
                        panic!("err when translating refmut:{:?}", e);
                    }
                }
            }
            Some((pa, _mp)) => {
                if pa.addr() == 0 || !_mp.contains(MappingFlags::P) {
                    let r = memory_set.handle_lazy_addr(
                        start_va.addr(),
                        TrapType::StorePageFault(start_va.addr()),
                    );
                    if r.is_err() {
                        if let Err(e) = memory_set.handle_cow_addr(start_va.addr()) {
                            panic!("err when translating refmut:{:?}", e);
                        }
                    }
                }
                if _mp.contains(MappingFlags::cow) && pa.addr() != 0 {
                    if let Err(e) = memory_set.handle_cow_addr(start_va.addr()) {
                        panic!("err when translating refmut:{:?}", e);
                    }
                }
            }
        }
        let mut end_va: VirtAddr = (vpn.to_addr() + PAGE_SIZE).into();
        end_va = end_va.min(VirtAddr::from(end));
        start = end_va.into();
    }
    unsafe { core::slice::from_raw_parts_mut(ptr, len) }
}

unsafe fn str_len(ptr: *const u8) -> usize {
    let mut i = 0;
    loop {
        if *ptr.add(i) == 0 {
            break i;
        }
        i += 1;
    }
}

/// Load a string from other address spaces into kernel space without an end `\0`.
pub fn translated_str(_token: PageTable, ptr: *const u8) -> String {
    unsafe {
        let len = str_len(ptr);
        from_utf8_unchecked(slice::from_raw_parts(ptr, len)).to_string()
    }
}

unsafe fn safe_str_len(memory_set: Arc<Mutex<MemorySet>>, ptr: *const u8) -> SysResult<usize> {
    let mut i = 0;
    Ok(loop {
        if *translated_ref(memory_set.clone(), ptr.add(i))? == 0 {
            break i;
        }
        i += 1;
    })
}
/// Load a string from other address spaces into kernel space without an end `\0`.
pub fn safe_translated_str(memory_set: Arc<Mutex<MemorySet>>, ptr: *const u8) -> SysResult<String> {
    unsafe {
        let len = safe_str_len(memory_set, ptr)?;
        Ok(from_utf8_unchecked(slice::from_raw_parts(ptr, len)).to_string())
    }
}
///
pub fn translated_ref<T>(
    memory_set: Arc<Mutex<MemorySet>>,
    ptr: *const T,
) -> SysResult<&'static T> {
    check_user_ptr(memory_set, ptr as usize, core::mem::size_of::<T>(), false)?;
    unsafe { Ok(ptr.as_ref().unwrap()) }
}
///
#[allow(unused)]
pub fn safe_translated_ref<T>(memory_set: Arc<Mutex<MemorySet>>, ptr: *const T) -> &'static T {
    let mut memory_set = memory_set.lock();
    let page_table = memory_set.page_table.clone();
    let va = VirtAddr::from(ptr as usize);
    match page_table.translate(va) {
        None => {
            let r = memory_set.handle_lazy_addr(va.addr(), TrapType::LoadPageFault(va.addr()));
            if r.is_err() {
                if let Err(e) = memory_set.handle_cow_addr(va.addr()) {
                    panic!("err when translating refmut:{:?}", e);
                }
            }
        }
        Some((pa, _mp)) => {
            if pa.addr() == 0 || !_mp.contains(MappingFlags::P) {
                let r = memory_set.handle_lazy_addr(va.addr(), TrapType::LoadPageFault(va.addr()));
                if r.is_err() {
                    if let Err(e) = memory_set.handle_cow_addr(va.addr()) {
                        panic!("err when translating refmut:{:?}", e);
                    }
                }
            }
        }
    }
    unsafe { ptr.as_ref().unwrap() }
}

