        }
    }
    //return a clone of Arc<dyn FileSystemType>
    pub fn find_fs(&self,name:&String)->Option<Arc<dyn FileSystemType>>{
        if let Some(fs_type) = self.file_systems.get(name){
            return Some(fs_type.clone());
        }
        return None;
    }

