    readers: BTreeSet<usize>,
    writer: Option<usize>,
    records: Vec<RecordLock>,
    waiters: alloc::collections::VecDeque<alloc::sync::Weak<TaskControlBlock>>,
}

#[derive(Clone, Copy)]
struct RecordLock {
    owner: usize,
    l_type: i16,
    start: i64,
    end: i64,
}

#[derive(Clone, Copy, Debug, Default)]
#[repr(C, packed)]
struct EpollEvent {
    events: u32,
    data: u64,
}

#[derive(Clone, Copy, Debug, Default)]
struct EpollWatchEntry {
    events: u32,
