    last_ready: u32,
    oneshot_delivered: bool,
}

lazy_static! {
    static ref FCNTL_LOCK_TABLE: spin::Mutex<BTreeMap<usize, FileAdvisoryLock>> =
        spin::Mutex::new(BTreeMap::new());
    static ref FLOCK_LOCK_TABLE: spin::Mutex<BTreeMap<usize, FileAdvisoryLock>> =
        spin::Mutex::new(BTreeMap::new());
    static ref EPOLL_WATCH_TABLE: spin::Mutex<BTreeMap<usize, BTreeMap<usize, EpollWatchEntry>>> =
        spin::Mutex::new(BTreeMap::new());
}

#[repr(C)]
#[derive(Clone, Copy)]
struct FlockArg {
    l_type: i16,
    l_whence: i16,
    l_start: i64,
    l_len: i64,
    l_pid: i32,
}

const F_RDLCK: i16 = 0;
const F_WRLCK: i16 = 1;
const F_UNLCK: i16 = 2;

fn flock_range(flock: &FlockArg, cur_offset: i64, file_size: i64) -> SysResult<(i64, i64)> {
    let base = match flock.l_whence {
        0 => 0,
        1 => cur_offset,
        2 => file_size,
        _ => return Err(SysError::EINVAL),
    };
    let start = base + flock.l_start;
    if start < 0 {
        return Err(SysError::EINVAL);
    }
    let end = if flock.l_len == 0 {
        i64::MAX
    } else {
        start + flock.l_len
    };
    if end < start {
        return Ok((end, start));
    }
    Ok((start, end))
}

fn record_locks_overlap(a_start: i64, a_end: i64, b_start: i64, b_end: i64) -> bool {
    a_start < b_end && b_start < a_end
}

fn file_lock_key(file: &Arc<dyn File>) -> SysResult<usize> {
    let inode = file
        .get_dentry()
        .get_inode()
        .map_err(|_| SysError::EINVAL)?;
    Ok(inode.get_meta().ino)
}

fn file_owner_key(file: &Arc<dyn File>) -> usize {
    file.get_inner() as *const _ as usize
}

fn release_advisory_locks_on_close(file: &Arc<dyn File>, pid: usize) {
    if let Ok(key) = file_lock_key(file) {
        let ofd_owner = file_owner_key(file);
        {
            let mut table = FCNTL_LOCK_TABLE.lock();
            let mut remove_entry = false;
            if let Some(state) = table.get_mut(&key) {
                state
                    .records
                    .retain(|lock| lock.owner != pid && lock.owner != ofd_owner);
                state.readers.remove(&pid);
                state.readers.remove(&ofd_owner);
                if state.writer == Some(pid) || state.writer == Some(ofd_owner) {
                    state.writer = None;
                }
                // 唤醒所有等待者
                while let Some(waiter) = state.waiters.pop_front() {
                    if let Some(task) = waiter.upgrade() {
                        crate::task::wakeup_task(task);
                    }
                }
                remove_entry =
                    state.records.is_empty() && state.readers.is_empty() && state.writer.is_none();
            }
            if remove_entry {
                table.remove(&key);
            }
        }
        {
            let mut table = FLOCK_LOCK_TABLE.lock();
            let mut remove_entry = false;
            if let Some(state) = table.get_mut(&key) {
                state.readers.remove(&ofd_owner);
                if state.writer == Some(ofd_owner) {
                    state.writer = None;
                }
                remove_entry = state.readers.is_empty() && state.writer.is_none();
            }
            if remove_entry {
                table.remove(&key);
            }
        }
    }
}

fn release_epoll_on_close(fd: usize) {
    let mut epolls = EPOLL_WATCH_TABLE.lock();
    epolls.remove(&fd);
    for watched in epolls.values_mut() {
        watched.remove(&fd);
    }
}

