pub fn sys_exit(exit_code: i32) -> ! {
    exit_current_and_run_next(exit_code << 8);
    panic!("Unreachable in sys_exit!");
}

pub fn sys_yield() -> SysResult<isize> {
    suspend_current_and_run_next();
    Ok(0)
}

pub fn sys_getpid() -> SysResult<isize> {
    let task = current_task().unwrap();
    let mut pid = task.pid;
    if pid == 0 {
        pid = task.gettid();
    }
    log::debug!("sys_getpid: tid={} pid={}", task.gettid(), pid);
    Ok(pid as isize)
}

pub fn sys_clone(
    flags: usize,
    stack_ptr: *const u8,
    ptid: *mut i32,
    mut _tls: *mut i32,
    mut ctid: *mut i32,
) -> SysResult<isize> {
    //   if stack_ptr as usize >= VIRT_ADDR_START || ptid as usize >= VIRT_ADDR_START || _tls as usize >= VIRT_ADDR_START || ctid as usize >= VIRT_ADDR_START{
    //     return Err(SysError::EFAULT);
    // }
    let tls = _tls;
    let ctid_ = ctid;
    #[cfg(target_arch = "riscv64")]
    {
        ctid = ctid_;
        _tls = tls;
    }
    #[cfg(target_arch = "loongarch64")]
    {
        ctid = tls;
        _tls = ctid_;
    }
    let flags_result = CloneFlags::from_bits(flags as u64 & !0xff);
    let signal = (flags & 0xff) as u32; // 提取低 8 位作为信号
    if flags_result.is_none() {
        error!("sys_clone: Invalid flags 0x{:x}", flags);
        return Err(SysError::EINVAL);
    }
    if signal != 0 && signal != 17 {
        // 只允许 SIGCHLD 或 0
        error!("sys_clone: Invalid signal 0x{:x}", signal);
        return Err(SysError::EINVAL);
    }
    let exit_signal = if signal == 0 { None } else { Some(signal) }; // 转换为 Option<u32>
    let flags = flags_result.unwrap();
    log::info!(
        "sys_clone: Parsed flags {:?}, signal {:?}",
        flags,
        exit_signal
    );
    let current_task = current_task().unwrap();
    //检查NPROC
    {
        let inner = current_task.inner_exclusive_access();
        if inner.resource_limit.nproc.is_some() {
            //println!("uid = {}",inner.uid);
            let nproc_limit = inner.resource_limit.nproc.unwrap().rlimit_cur;
            let uid = inner.uid;
            //println!("uid {} limit {}",uid,nproc_limit);
            let uid_tree = &task::UID4NPROC.lock().record;
            let n = uid_tree.get(&uid).unwrap();
            if uid > 0 && n >= &nproc_limit {
                //非root
                return Err(SysError::EAGAIN);
            }
        }
    }
    let new_task = current_task.fork(flags, stack_ptr as usize, ctid, false, exit_signal);
    let new_tid = new_task.tid.0;
    let _parent_pgid = current_task.inner_exclusive_access().pgid;
    log::info!("sys_clone: Created new task with TID {}", new_tid);
    //println!("sys_clone: Parent tid={} pid={} pgid={}", current_task.gettid(), current_task.getpid(), parent_pgid);
    //println!("sys_clone: tid={} flags={:?}, signal={:?}", current_task.gettid(), flags_result, exit_signal);
    //println!("sys_clone: Created child tid={} pid={}", new_tid, new_task.getpid());

