static TCP_RECV_HOOK: spin::Mutex<Option<fn(u16)>> = spin::Mutex::new(None);

pub fn set_udp_recv_hook(hook: fn(u16)) {
    *UDP_RECV_HOOK.lock() = Some(hook);
}

pub fn set_tcp_recv_hook(hook: fn(u16)) {
    *TCP_RECV_HOOK.lock() = Some(hook);
}

pub(crate) fn notify_udp_recv(port: u16) {
    let hook = *UDP_RECV_HOOK.lock();
    if let Some(hook) = hook {
        hook(port);
    }
}

pub(crate) fn notify_tcp_recv(port: u16) {
    let hook = *TCP_RECV_HOOK.lock();
    if let Some(hook) = hook {
        hook(port);
    }
}

