/// port → list of task tids blocked in poll/select waiting for data on this port.
static POLL_WAITERS: Lazy<Mutex<BTreeMap<u16, Vec<usize>>>> = Lazy::new(|| Mutex::new(BTreeMap::new()));

fn wakeup_pollers(port: u16) {
    let mut map = POLL_WAITERS.lock();
    if let Some(tids) = map.remove(&port) {
        for tid in &tids {
            if let Some(task) = tid2task(*tid) {
                wakeup_task(task);
            }
        }
    }
}

pub fn init_socket_hooks() {
    lose_net_stack::set_udp_recv_hook(wakeup_pollers);
    lose_net_stack::set_tcp_recv_hook(wakeup_pollers);
}

/// Register current task as a poll waiter for the given port.
/// Called by sys_poll before blocking.
pub fn register_poll_waiter(port: u16) {
    let tid = current_task().map(|t| t.gettid()).unwrap_or(0);
    let mut map = POLL_WAITERS.lock();
    map.entry(port).or_default().push(tid);
}

/// Deregister current task from all poll waiter entries.
/// Called by sys_poll after waking up from block.
pub fn deregister_poll_waiters() {
    let tid = current_task().map(|t| t.gettid()).unwrap_or(0);
    let mut map = POLL_WAITERS.lock();
    let mut empty_ports = Vec::new();
    for (port, tids) in map.iter_mut() {
        tids.retain(|t| *t != tid);
        if tids.is_empty() {
            empty_ports.push(*port);
        }
    }
    for port in empty_ports {
        map.remove(&port);
    }
}

/// Try to extract the local port from a socket file descriptor.
/// Returns None if fd is not a socket or the socket isn't bound.
pub fn try_get_socket_port(file: &Arc<dyn File>) -> Option<u16> {
    // Clone Arc and try downcast; if it fails we get back the Arc<dyn File>.
    match Arc::clone(file).downcast_arc::<Socket>() {
        Ok(socket) => socket.inner.get_local().ok().map(|a| a.port()),
        Err(_) => None,
    }
}

