pub fn syscall(syscall_id: usize, args: [usize; 6]) -> isize {
    // let ttid = current_task().unwrap().gettid();
    // if syscall_id!=260{
    //     println!("syscallid:{}",syscall_id);
    // }
    //     if ttid==3{
    //     println!("syscallid:{} {}",syscall_id,ttid);
    // }
    let result: SysResult<isize>;
    match syscall_id {
        SYSCALL_POWEROFF => {
            ext4::disk_sync();
            arch::shutdown();
        }
        SYSCALL_IOCTL => {
            result = sys_ioctl(args[0] as isize, args[1] as isize, args[2] as *mut usize);
        }
        SYSCALL_IOPRIO_SET => {
            result = sys_ioprio_set(args[0] as c_int, args[1] as c_int, args[2] as c_int);
        }
        SYSCALL_IOPRIO_GET => {
            result = sys_ioprio_get(args[0] as c_int, args[1] as c_int);
        }
        SYSCALL_CHDIR => {
            result = sys_chdir(args[0] as *const u8);
        }
        SYSCALL_FCHDIR => {
            result = sys_fchdir(args[0] as c_uint);
        }
        SYSCALL_CHROOT => {
            result = sys_chroot(args[0] as *const u8);
        }
        SYSCALL_FCHMOD => {
            result = sys_fchmod(args[0], args[1]);
        }
        SYSCALL_FCHOWN => {
            result = sys_fchown(args[0], args[1] as i32, args[2] as i32);
        }
        SYSCALL_FCHMODAT => {
            result = sys_fchmodat(args[0], args[1] as *const u8, args[2], args[3] as i32);
        }
        SYSCALL_FCHMODAT2 => {
            result = sys_fchmodat(args[0], args[1] as *const u8, args[2], args[3] as i32);
        }
        SYSCALL_FCHOWNAT => {
            result = sys_fchownat(
                args[0],
                args[1] as *const u8,
                args[2] as i32,
                args[3] as i32,
                args[4] as i32,
            );
        }
        SYSCALL_GETGROUPS => {
            result = sys_getgroups(args[0], args[1] as *mut u32);
        }
        SYSCALL_SETGROUPS => {
            result = sys_setgroups(args[0], args[1] as *mut u32);
        }
        SYSCALL_LINKAT => {
            result = sys_link(
                args[0] as isize,
                args[1] as *const u8,
                args[2] as isize,
                args[3] as *const u8,
                args[4] as u32,
            );
        }
        SYSCALL_UNLINKAT => {
            result = sys_unlink(args[0] as isize, args[1] as *const u8, args[2] as u32);
        }
        SYSCALL_SYMLINKAT => {
            result = sys_symlinkat(args[0] as *const u8, args[1] as isize, args[2] as *const u8);
        }
        SYSCALL_MKDIRAT => {
            result = sys_mkdirat(args[0] as isize, args[1] as *const u8, args[2] as u32);
        }
        SYSCALL_OPENAT => {
            result = sys_openat(
                args[0] as isize,
                args[1] as *const u8,
                args[2] as u32,
                args[3] as u32,
            );
        }
        SYSCALL_CLOSE => {
            result = sys_close(args[0]);
            log_debug!("syscall_close  closed:{}", args[0]);
        }
        SYSCALL_VHANGUP => {
            result = sys_vhangup();
        }
        SYSCALL_READ => {
            result = sys_read(args[0], args[1] as *mut u8, args[2]);
            //      log_debug!("syscall_read result:{}",result);
        }
        SYSCALL_WRITE => {
            result = sys_write(args[0], args[1] as *mut u8, args[2]);
            //      log_debug!("syscall_write result:{}",result);
        }
        SYSCALL_READV => {
            result = sys_readv(args[0] as isize, args[1] as *const IoVec, args[2]);
        }
        SYSCALL_WRITEV => {
            result = sys_writev(args[0] as isize, args[1] as *const IoVec, args[2]);
        }
        SYSCALL_PREAD64 => {
            result = sys_pread64(args[0], args[1] as *mut u8, args[2], args[3] as isize);
        }
        SYSCALL_PWRITE64 => {
            result = sys_pwrite64(args[0], args[1] as *mut u8, args[2], args[3] as isize);
        }
        SYSCALL_PREADV => {
            result = sys_preadv(
                args[0] as isize,
                args[1] as *const IoVec,
                args[2],
                args[3] as isize,
            );
        }
        SYSCALL_PWRITEV => {
            result = sys_pwritev(
                args[0] as isize,
                args[1] as *const IoVec,
                args[2],
                args[3] as isize,
            );
        }
        SYSCALL_PREADV2 => {
            let offset = (args[3] as u64 | ((args[4] as u64) << 32)) as isize;
            result = sys_preadv2(
                args[0] as isize,
                args[1] as *const IoVec,
                args[2],
                offset,
                args[5] as i32,
            );
        }
        SYSCALL_PWRITEV2 => {
            let offset = (args[3] as u64 | ((args[4] as u64) << 32)) as isize;
            result = sys_pwritev2(
                args[0] as isize,
                args[1] as *const IoVec,
                args[2],
                offset,
                args[5] as i32,
            );
        }
        SYSCALL_EXIT => {
            let pid = current_task().unwrap().gettid();
            log_debug!("syscall_exit exit code:{} tid:{}", args[0], pid);
            sys_exit(args[0] as i32);
        }
        SYSCALL_SCHED_GETAFFINITY => {
            result = sys_sched_gettaffinity(args[0], args[1], args[2] as *mut usize)
        }
        SYSCALL_SCHED_SETAFFINITY => {
            result = sys_sched_settaffinity(args[0], args[1], args[2] as *const usize)
        }
        SYSCALL_YIELD => {
            //    log_debug!("syscall_yield");
            result = sys_yield();
        }
        SYSCALL_KILL => {
            log_debug!("syscall_kill pid={} signal={}", args[0], args[1]);
            result = sys_kill(args[0], args[1]);
        }
        SYSCALL_SIGACTION => {
            result = sys_sigaction(args[0], args[1] as *const _, args[2] as *mut _, args[3]);
        }
        SYSCALL_SIGPROCMASK => {
            result = sys_sigprocmask(args[0] as i32, args[1] as *const _, args[2] as *mut _, args[3]);
        }
        SYSCALL_RT_SIGQUEUEINFO => {
            result = sys_rt_sigqueueinfo(args[0] as i32, args[1] as i32, args[2] as *const u8);
        }
        SYSCALL_SIGPENDING => {
            result = sys_sigpending(args[0] as *mut SignalFlags, args[1]);
        }
        SYSCALL_SIGRETURN => {
            result = sys_sigreturn();
        }
        SYSCALL_GET_TIME => {
            result = sys_get_time(args[0] as *mut time::TimeVal, args[1]);
        }
        SYSCALL_SETTIMEOFDAY => {
            result = sys_settimeofday(args[0] as *mut time::TimeVal, args[1]);
        }
        SYSCALL_ADJTIMEX => {
            result = sys_adjtimex(args[0] as *mut KernelTimex);
        }
        SYSCALL_GETPID => {
            result = sys_getpid();
        }
        SYSCALL_CLONE => {
            result = sys_clone(
                args[0],
                args[1] as *const u8,
                args[2] as *mut i32,
                args[3] as *mut i32,
                args[4] as *mut i32,
            );
        }
        SYSCALL_EXEC => {
            result = sys_exec(
                args[0] as *const u8,
                args[1] as *const usize,
                args[2] as *const usize,
            );
        }

