        "max_user_namespaces",
        InodeMode::FILE | InodeMode::all_perm(),
        0,
        0,
    )?;
    let maxns_file = maxns_dentry.open(OpenFlags::RDWR);
    let _ = maxns_file.write("0\n".as_bytes());

    // /proc/sys/net/ipv4/ 供 LTP cve-2022-4378 使用
    let net_dentry = sys_dentry.create(
        "net",
        InodeMode::DIR | InodeMode::all_perm(),
