fn update_hardware_timer() {
    let freq = arch::time::Time::get_freq() as i64;
    let now_ticks = arch::time::Time::now().raw();
    // 周期抢占间隔（与 set_next_timeout 的 CLOCK_FREQ/100 = 10ms 一致）。
    // 硬件定时器最远不超过一个周期，保证时钟中断至少每 10ms 触发一次，
    // 使 maybe_preempt / check_itimer 不会被 TIMERS 中“未过期但 expire 较远”
    // 的 futex/stopped 定时器覆盖而停摆（否则依赖抢占的进程，如 setitimer/
    // 忙等场景，会因周期中断被推迟而卡死）。
    let period_ticks = now_ticks + (freq as usize) / 100;
    let mut set_ticks = period_ticks;
    if let Some(earliest) = TIMERS.lock().peek() {
        let expire_ns = earliest.expire.sec as i64 * 1_000_000_000 + earliest.expire.nsec as i64;
        if expire_ns > 0 {
            let expire_ticks = (expire_ns * freq / 1_000_000_000) as usize;
            // 如果最早定时器已过期，设到 1 tick 后，避免立即中断造成
            // check_futex_timer defer 循环（过期定时器被反复 defer → 立即中断 → defer...）
            let e = if expire_ticks <= now_ticks {
                now_ticks + 1
            } else {
                expire_ticks
            };
            // 取较近者：既保证 futex 超时精度，又不让抢占被推迟超过一个周期
            set_ticks = set_ticks.min(e);
        }
    }
    arch::set_timer(set_ticks);
}

