    fn drop(&mut self) {
        let mut rb = self.buffer.lock();
        if let Some(waiter) = rb.writer_waiter.take().and_then(|w| w.upgrade()) {
            wakeup_task(waiter);
        }
        if let Some(waiter) = rb.reader_waiter.take().and_then(|w| w.upgrade()) {
            wakeup_task(waiter);
        }
    }
}

